INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_1_desc', 'Learn Visually. Master Permanently. Your visual learning companion powered by SM-2 science.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_2_title', 'How old are you?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_2_desc', 'This helps us personalize your learning experience and recommend the right subjects.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_3_title', 'What do you want to master?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_3_desc', 'Select your primary interest to customize your initial dashboard.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_4_title', 'Create & Share') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_4_desc', 'Build your own deck or dive into cards shared by Aliolo learners worldwide. Learn at your pace, then test yourself when you''re ready.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_5_title', 'Master Anywhere') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_5_desc', 'Your library stays in sync across all your devices. We’ll only nudge you when it’s time to protect your streak.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_6_title', 'Join the Community') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_6_desc', 'Start your journey today and master anything you set your mind to.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('en', 'onboarding_7_quote', 'Aliolo has completely transformed the way my children and I master new topics. The visual cards and spaced repetition make learning feel like a game!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
