INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_1_title', 'Selamat Datang di Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_1_desc', 'Belajar Secara Visual. Kuasai Secara Permanen. Pendamping belajar visual Anda yang didukung oleh sains SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_2_title', 'Berapa usia Anda?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_2_desc', 'Ini membantu kami mempersonalisasi pengalaman belajar Anda dan merekomendasikan mata pelajaran yang tepat.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_3_title', 'Apa yang ingin Anda kuasai?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_3_desc', 'Pilih minat utama Anda untuk menyesuaikan dasbor awal Anda.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_4_title', 'Buat & Bagikan') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_4_desc', 'Bangun dek Anda sendiri atau selami kartu yang dibagikan oleh pelajar Aliolo di seluruh dunia. Belajar sesuai kecepatan Anda, lalu uji diri Anda saat siap.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_5_title', 'Kuasai di Mana Saja') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_5_desc', 'Perpustakaan Anda tetap sinkron di semua perangkat Anda. Kami hanya akan mengingatkan Anda saat waktunya melindungi streak Anda.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_6_title', 'Bergabunglah dengan Komunitas') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_6_desc', 'Mulailah perjalanan Anda hari ini dan kuasai apa pun yang Anda inginkan.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_7_quote', 'Aliolo telah sepenuhnya mengubah cara anak-anak saya dan saya menguasai topik baru. Kartu visual dan pengulangan berjarak membuat belajar terasa seperti permainan!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('id', 'onboarding_7_joined', 'Bergabung dengan ribuan pelajar') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
