INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_1_title', 'Добре дошли в Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_1_desc', 'Учете визуално. Овладейте перманентно. Вашият спътник за визуално обучение, задвижван от науката SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_2_title', 'На колко години сте?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_2_desc', 'Това ни помага да персонализираме вашето учебно изживяване и да препоръчаме правилните предмети.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_3_title', 'Какво искате да овладеете?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_3_desc', 'Изберете основния си интерес, за да персонализирате началното си табло.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_4_title', 'Създавайте и споделяйте') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_4_desc', 'Изградете своя собствена колода или се потопете в карти, споделени от учащи в Aliolo по целия свят. Учете със свое собствено темпо, след което се тествайте, когато сте готови.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_5_title', 'Овладявайте навсякъде') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_5_desc', 'Вашата библиотека остава синхронизирана на всички ваши устройства. Ще ви подсещаме само когато е време да защитите серията си.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_6_title', 'Присъединете се към общността') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_6_desc', 'Започнете своето пътуване днес и овладейте всичко, което си наумите.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_7_quote', 'Aliolo напълно трансформира начина, по който децата ми и аз овладяваме нови теми. Визуалните карти и интервалното повторение правят ученето да изглежда като игра!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('bg', 'onboarding_7_joined', 'Присъединиха се хиляди учащи') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
