INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_1_title', 'Vítejte v Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_1_desc', 'Učte se vizuálně. Ovládejte trvale. Váš vizuální společník pro učení poháněný vědou SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_2_title', 'Kolik vám je let?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_2_desc', 'To nám pomůže přizpůsobit vaše učení a doporučit ty správné předměty.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_3_title', 'Co chcete ovládnout?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_3_desc', 'Vyberte svůj primární zájem a přizpůsobte si úvodní panel.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_4_title', 'Vytvářejte a sdílejte') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_4_desc', 'Sestavte si vlastní balíček nebo se ponořte do karet sdílených studenty Aliolo po celém světě. Učte se vlastním tempem a otestujte se, až budete připraveni.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_5_title', 'Ovládejte kdekoli') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_5_desc', 'Vaše knihovna zůstává synchronizovaná ve všech vašich zařízeních. Upozorníme vás, jen když bude čas chránit vaši sérii.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_6_title', 'Připojte se ke komunitě') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_6_desc', 'Začněte svou cestu dnes a ovládněte cokoli, co si předsevzete.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_7_quote', 'Aliolo zcela změnilo způsob, jakým moje děti i já ovládáme nová témata. Vizuální karty a rozložené opakování dělají z učení hru!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('cs', 'onboarding_7_joined', 'Připojily se tisíce studentů') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
