INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_1_title', 'Velkommen til Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_1_desc', 'Lær visuelt. Mestre permanent. Din visuelle læringskammerat drevet af SM-2 videnskab.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_2_title', 'Hvor gammel er du?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_2_desc', 'Dette hjælper os med at personliggøre din læringsoplevelse og anbefale de rigtige emner.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_3_title', 'Hvad vil du mestre?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_3_desc', 'Vælg din primære interesse for at tilpasse dit indledende instrumentbræt.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_4_title', 'Opret og del') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_4_desc', 'Byg dit eget dæk eller dyk ned i kort delt af Aliolo-lærende over hele verden. Lær i dit eget tempo, og test dig selv, når du er klar.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_5_title', 'Mestre overalt') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_5_desc', 'Dit bibliotek forbliver synkroniseret på tværs af alle dine enheder. Vi giver dig kun et puf, når det er tid til at beskytte din streak.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_6_title', 'Bliv en del af fællesskabet') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_6_desc', 'Start din rejse i dag og mestre alt, hvad du sætter dig for.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_7_quote', 'Aliolo har fuldstændig ændret den måde, mine børn og jeg mestrer nye emner på. De visuelle kort og spaced repetition får læring til at føles som en leg!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('da', 'onboarding_7_joined', 'Deltaget af tusindvis af lærende') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
