INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_1_title', 'Willkommen bei Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_1_desc', 'Visuell lernen. Dauerhaft meistern. Dein visueller Lernbegleiter, basierend auf SM-2-Wissenschaft.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_2_title', 'Wie alt bist du?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_2_desc', 'Dies hilft uns, dein Lernerlebnis zu personalisieren und die richtigen Themen zu empfehlen.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_3_title', 'Was möchtest du meistern?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_3_desc', 'Wähle dein Hauptinteresse aus, um dein initiales Dashboard anzupassen.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_4_title', 'Erstellen & Teilen') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_4_desc', 'Erstelle dein eigenes Deck oder tauche in Karten ein, die von Aliolo-Lernern weltweit geteilt werden. Lerne in deinem Tempo und teste dich selbst, wenn du bereit bist.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_5_title', 'Überall meistern') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_5_desc', 'Deine Bibliothek bleibt auf allen deinen Geräten synchron. Wir erinnern dich nur, wenn es Zeit ist, deine Serie zu schützen.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_6_title', 'Tritt der Community bei') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_6_desc', 'Beginne deine Reise heute und meistere alles, was du dir vornimmst.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_7_quote', 'Aliolo hat die Art und Weise, wie meine Kinder und ich neue Themen meistern, völlig verändert. Die visuellen Karten und die abgestufte Wiederholung lassen das Lernen wie ein Spiel erscheinen!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_7_joined', 'Tausende von Lernern sind dabei') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_next', 'Weiter') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('de', 'onboarding_skip', 'Überspringen') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
