INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_1_title', 'Tere tulemast Aliolosse') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_1_desc', 'Õpi visuaalselt. Omanda jäädavalt. Sinu visuaalne õpikaaslane, mis põhineb SM-2 teadusel.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_2_title', 'Kui vana sa oled?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_2_desc', 'See aitab meil sinu õpikogemust personaliseerida ja soovitada õigeid teemasid.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_3_title', 'Mida sa soovid omandada?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_3_desc', 'Vali oma peamine huvi, et kohandada oma algset töölauda.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_4_title', 'Loo ja jaga') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_4_desc', 'Koosta oma kaardipakk või süvene kaartidesse, mida jagavad Aliolo õppijad üle maailma. Õpi oma tempos ja pane end proovile, kui oled valmis.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_5_title', 'Omanda kõikjal') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_5_desc', 'Sinu raamatukogu püsib kõigis seadmetes sünroonis. Anname sulle märku vaid siis, kui on aeg kaitsta oma õpijärge.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_6_title', 'Liitu kogukonnaga') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_6_desc', 'Alusta oma teekonda täna ja omanda kaikki, mille ette võtad.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_7_quote', 'Aliolo on täielikult muutnud viisi, kuidas mina ja minu lapsed uusi teemasid omandame. Visuaalsed kaardid ja kordamine teevad õppimisest mängu!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_7_joined', 'Liitunud tuhandete õppijatega') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_next', 'Edasi') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'onboarding_skip', 'Jäta vahele') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'compare_plans', 'Võrdle tasuta ja Premium paketti') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('et', 'hide_comparison', 'Peida pakettide võrdlus') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
