INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_1_title', 'Bienvenido a Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_1_desc', 'Aprende visualmente. Domina permanentemente. Tu compañero de aprendizaje visual impulsado por la ciencia SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_2_title', '¿Qué edad tienes?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_2_desc', 'Esto nos ayuda a personalizar tu experiencia de aprendizaje y recomendarte los temas adecuados.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_3_title', '¿Qué quieres dominar?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_3_desc', 'Selecciona tu interés principal para personalizar tu panel inicial.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_4_title', 'Crear y Compartir') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_4_desc', 'Crea tu propio mazo o sumérgete en las cartas compartidas por estudiantes de Aliolo en todo el mundo. Aprende a tu ritmo y luego ponte a prueba cuando estés listo.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_5_title', 'Domina en cualquier lugar') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_5_desc', 'Tu biblioteca se mantiene sincronizada en todos tus dispositivos. Solo te daremos un toque cuando sea el momento de proteger tu racha.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_6_title', 'Únete a la comunidad') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_6_desc', 'Comienza tu viaje hoy y domina cualquier cosa que te propongas.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_7_quote', 'Aliolo ha transformado completamente la forma en que mis hijos y yo dominamos nuevos temas. ¡Las tarjetas visuales y la repetición espaciada hacen que el aprendizaje parezca un juego!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('es', 'onboarding_7_joined', 'Se han unido miles de estudiantes') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
