INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_1_title', 'Bienvenue sur Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_1_desc', 'Apprenez visuellement. Maîtrisez durablement. Votre compagnon d''apprentissage visuel propulsé par la science SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_2_title', 'Quel âge avez-vous ?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_2_desc', 'Cela nous aide à personnaliser votre expérience d''apprentissage et à recommander les bons sujets.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_3_title', 'Que voulez-vous maîtriser ?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_3_desc', 'Sélectionnez votre intérêt principal pour personnaliser votre tableau de bord initial.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_4_title', 'Créer & Partager') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_4_desc', 'Créez votre propre jeu ou plongez dans les cartes partagées par les apprenants Aliolo du monde entier. Apprenez à votre rythme, puis testez-vous quand vous êtes prêt.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_5_title', 'Maîtrisez n''importe où') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_5_desc', 'Votre bibliothèque reste synchronisée sur tous vos appareils. Nous ne vous solliciterons que lorsqu''il sera temps de protéger votre série.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_6_title', 'Rejoignez la communauté') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_6_desc', 'Commencez votre voyage aujourd''hui et maîtrisez tout ce que vous entreprenez.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_7_quote', 'Aliolo a complètement transformé la façon dont mes enfants et moi maîtrisons de nouveaux sujets. Les cartes visuelles et la répétition espacée font de l''apprentissage un jeu !') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_7_joined', 'Rejoint par des milliers d''apprenants') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_next', 'Suivant') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fr', 'onboarding_skip', 'Passer') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
