INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_1_title', 'Fáilte go Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_1_desc', 'Foghlaim go hAmhairc. Máistreacht go Buan. Do chompánach foghlama amhairc bunaithe ar eolaíocht SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_2_title', 'Cén aois thú?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_2_desc', 'Cabhraíonn sé seo linn do thaithí foghlama a phearsantú agus na hábhair chearta a mholadh.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_3_title', 'Cad ba mhaith leat a mháistir?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_3_desc', 'Roghnaigh do phríomhspéis chun do dheais tosaigh a shaincheapadh.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_4_title', 'Cruthaigh & Comhroinn') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_4_desc', 'Tóg do dheic féin nó tumadh isteach i gcártaí roinnte ag foghlaimeoirí Aliolo ar fud an domhain. Foghlaim ar do luas féin, ansin déan tástáil ort féin nuair a bhíonn tú réidh.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_5_title', 'Máistreacht áit ar bith') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_5_desc', 'Fanann do leabharlann sioncronaithe ar do ghléasanna go léir. Ní thabharfaimid leid duit ach nuair a bheidh sé in am do stríoc a chosaint.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_6_title', 'Bí sa Phobal') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_6_desc', 'Tosaigh do thuras inniu agus máistir rud ar bith a chuireann tú d''intinn chuige.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_7_quote', 'D''athraigh Aliolo go hiomlán an bealach a n-éiríonn liom féin agus mo pháistí máistreacht a fháil ar thopaicí nua. Is cosúil le cluiche é an fhoghlaim mar gheall ar na cártaí amhairc!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_7_joined', 'Na mílte foghlaimeoirí tar éis dul isteach') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_next', 'Ar aghaidh') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'onboarding_skip', 'Scipeáil') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'compare_plans', 'Déan comparáid idir Saor in aisce agus Préimh') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ga', 'hide_comparison', 'Folaigh Comparáid Plean') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
