INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_1_title', 'Dobrodošli u Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_1_desc', 'Učite vizualno. Savladajte trajno. Vaš pratitelj za vizualno učenje potpomognut SM-2 znanošću.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_2_title', 'Koliko imate godina?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_2_desc', 'To nam pomaže personalizirati vaše iskustvo učenja i preporučiti prave predmete.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_3_title', 'Što želite savladati?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_3_desc', 'Odaberite svoj primarni interes kako biste prilagodili svoju početnu nadzornu ploču.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_4_title', 'Stvorite i podijelite') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_4_desc', 'Sastavite vlastiti špil ili uronite u kartice koje dijele Aliolo polaznici diljem svijeta. Učite svojim tempom, a zatim se testirajte kada budete spremni.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_5_title', 'Savladajte bilo gdje') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_5_desc', 'Vaša knjižnica ostaje sinkronizirana na svim vašim uređajima. Podsjetit ćemo vas samo kada bude vrijeme da zaštitite svoj niz.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_6_title', 'Pridružite se zajednici') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_6_desc', 'Započnite svoje putovanje danas i savladajte sve što naumite.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_7_quote', 'Aliolo je potpuno transformirao način na koji moja djeca i ja svladavamo nove teme. Vizualne kartice i ponavljanje u razmacima čine učenje igrom!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hr', 'onboarding_7_joined', 'Pridružile su se tisuće polaznika') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
