INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_1_title', 'Benvenuti su Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_1_desc', 'Impara visivamente. Padroneggia permanentemente. Il tuo compagno di apprendimento visivo alimentato dalla scienza SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_2_title', 'Quanti anni hai?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_2_desc', 'Questo ci aiuta a personalizzare la tua esperienza di apprendimento e consigliare i soggetti giusti.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_3_title', 'Cosa vuoi padroneggiare?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_3_desc', 'Seleziona il tuo interesse primario per personalizzare la tua dashboard iniziale.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_4_title', 'Crea e Condividi') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_4_desc', 'Costruisci il tuo mazzo o tuffati nelle carte condivise dagli studenti di Aliolo in tutto il mondo. Impara al tuo ritmo, poi mettiti alla prova quando sei pronto.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_5_title', 'Padroneggia Ovunque') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_5_desc', 'La tua libreria rimane sincronizzata su tutti i tuoi dispositivi. Ti avviseremo solo quando sarà il momento di proteggere la tua serie.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_6_title', 'Unisciti alla Community') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_6_desc', 'Inizia il tuo viaggio oggi e padroneggia tutto ciò che ti prefiggi.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_7_quote', 'Aliolo ha completamente trasformato il modo in cui io e i miei figli padroneggiamo nuovi argomenti. Le carte visive e la ripetizione spaziata fanno sembrare l''apprendimento un gioco!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('it', 'onboarding_7_joined', 'Uniti a migliaia di studenti') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
