INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_1_title', 'Laipni lūdzam Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_1_desc', 'Mācieties vizuāli. Apgūstiet paliekoši. Jūsu vizuālais mācību biedrs, kura pamatā ir SM-2 zinātne.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_2_title', 'Cik jums ir gadu?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_2_desc', 'Tas palīdz mums personalizēt jūsu mācību pieredzi un ieteikt piemērotākos priekšmetus.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_3_title', 'Ko jūs vēlaties apgūt?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_3_desc', 'Izvēlieties savu galveno interesi, lai pielāgotu sākotnējo informācijas paneli.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_4_title', 'Izveidojiet un kopīgojiet') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_4_desc', 'Izveidojiet savu kāršu komplektu vai iedziļinieties kartītēs, ar kurām dalās Aliolo lietotāji visā pasaulē. Mācieties savā tempā un pēc tam pārbaudiet sevi, kad esat gatavs.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_5_title', 'Apgūstiet jebkur') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_5_desc', 'Jūsu bibliotēka tiek sinhronizēta visās jūsu ierīcēs. Mēs jūs mudināsim tikai tad, kad būs laiks aizsargāt savu sēriju.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_6_title', 'Pievienojieties kopienai') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_6_desc', 'Sāciet savu ceļojumu šodien un apgūstiet visu, ko esat iecerējis.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_7_quote', 'Aliolo ir pilnībā mainījis veidu, kā es un mani bērni apgūstam jaunas tēmas. Vizuālās kartītes un intervālu atkārtošana liek mācībām justies kā spēlei!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lv', 'onboarding_7_joined', 'Pievienojušies tūkstošiem izglītojamo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
