INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_1_title', 'Sveiki atvykę į Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_1_desc', 'Mokykitės vizualiai. Įsisavinkite visam laikui. Jūsų vizualaus mokymosi palydovas, pagrįstas SM-2 mokslu.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_2_title', 'Kiek jums metų?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_2_desc', 'Tai padeda mums personalizuoti jūsų mokymosi patirtį ir rekomenduoti tinkamus dalykus.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_3_title', 'Ką norite įsisavinti?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_3_desc', 'Pasirinkite pagrindinį interesą, kad pritaikytumėte pradinį prietaisų skydelį.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_4_title', 'Kurkite ir dalinkitės') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_4_desc', 'Susikurkite savo rinkinį arba pasinerkite į korteles, kuriomis dalijasi Aliolo mokiniai visame pasaulyje. Mokykitės savo tempu, tada išbandykite save, kai būsite pasiruošę.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_5_title', 'Įsisavinkite bet kur') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_5_desc', 'Jūsų biblioteka sinchronizuojama visuose įrenginiuose. Priminsime tik tada, kai ateis laikas apsaugoti savo seriją.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_6_title', 'Prisijunkite prie bendruomenės') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_6_desc', 'Pradėkite savo kelionę šiandien ir įsisavinkite viską, ką užsibrėžėte.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_7_quote', 'Aliolo visiškai pakeitė tai, jak aš ir mano vaikai įsisaviname naujas temas. Vizualios kortelės ir pasikartojimai daro mokymąsi panašų į žaidimą!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('lt', 'onboarding_7_joined', 'Prisijungė tūkstančiai mokinių') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
