INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_1_title', 'Üdvözöljük az Aliolo világában') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_1_desc', 'Tanuljon vizuálisan. Sajátítsa el véglegesen. Vizuális tanulási társa az SM-2 tudomány erejével.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_2_title', 'Hány éves vagy?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_2_desc', 'Ez segít nekünk személyre szabni a tanulási élményt, és a megfelelő tantárgyakat ajánlani.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_3_title', 'Mit szeretnél elsajátítani?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_3_desc', 'Válaszd ki az elsődleges érdeklődési körödet a kezdő irányítópult testreszabásához.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_4_title', 'Létrehozás és megosztás') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_4_desc', 'Építsd fel saját paklidat, vagy merülj el az Aliolo tanulók által világszerte megosztott kártyákban. Tanulj a saját tempódban, majd teszteld magad, amikor készen állsz.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_5_title', 'Sajátítsa el bárhol') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_5_desc', 'A könyvtárad minden eszközödön szinkronban marad. Csak akkor fogunk figyelmeztetni, amikor ideje megvédeni a sorozatodat.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_6_title', 'Csatlakozz a közösséghez') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_6_desc', 'Kezdje el az utazást ma, és sajátítson el bármit, amit elhatározott.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_7_quote', 'Az Aliolo teljesen átalakította a gyermekeim és az én tanulási módszereinket. A vizuális kártyák és az ismétlés játéknak tűnik a tanulás közben!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_7_joined', 'Tanulók ezrei csatlakoztak már') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_next', 'Tovább') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hu', 'onboarding_skip', 'Kihagyás') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
