INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_1_title', 'Merħba f''Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_1_desc', 'Tgħallem Viżwalment. Ikkontrolla b''mod Permanenti. Il-kumpann tat-tagħlim viżwali tiegħek imħaddem mix-xjenza SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_2_title', 'Kemm għandek żmien?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_2_desc', 'Dan jgħinna nippersonalizzaw l-esperjenza tat-tagħlim tiegħek u nirrakkomandaw is-suġġetti t-tajba.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_3_title', 'X''tixtieq tikkontrolla?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_3_desc', 'Agħżel l-interess primarju tiegħek biex tippersonalizza d-dashboard inizjali tiegħek.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_4_title', 'Oħloq u Aqsam') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_4_desc', 'Ibni l-gverta tiegħek jew idħol f''karti maqsuma mill-istudenti ta'' Aliolo madwar id-dinja. Tgħallem bil-pass tiegħek, imbagħad ittestja lilek innifsek meta tkun lest.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_5_title', 'Ikkontrolla Kullimkien') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_5_desc', 'Il-librerija tiegħek tibqa'' sinkronizzata fl-apparati kollha tiegħek. Aħna ninfurmak biss meta jkun wasal iż-żmien li tipproteġi l-istreak tiegħek.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_6_title', 'Ingħaqad mal-Komunità') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_6_desc', 'Ibda l-vjaġġ tiegħek illum u kkontrolla kull ħaġa li tpoġġi f''moħħok.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('mt', 'onboarding_7_quote', 'Aliolo bidlet kompletament il-mod kif uliedi u jien nikkontrollaw suġġetti ġodda. Il-karti viżwali u r-ripetizzjoni jagħmlu t-tagħlim iħossu bħal logħba!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
