INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_1_title', 'Welkom bij Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_1_desc', 'Leer Visueel. Beheers Permanent. Je visuele leerpartner aangedreven door SM-2-wetenschap.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_2_title', 'Hoe oud ben je?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_2_desc', 'Dit helpt ons je leerervaring te personaliseren en de juiste onderwerpen aan te bevelen.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_3_title', 'Wat wil je beheersen?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
