INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_4_title', 'Creëren & Delen') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_4_desc', 'Bouw je eigen deck of duik in kaarten die worden gedeeld door Aliolo-leerlingen wereldwijd. Leer in je eigen tempo en test jezelf wanneer je er klaar voor bent.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
