INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_5_desc', 'Je bibliotheek blijft gesynchroniseerd op al je apparaten. We geven je alleen een seintje als het tijd is om je streak te beschermen.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_6_title', 'Word lid van de Community') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_6_desc', 'Begin vandaag nog aan je reis en beheers alles wat je van plan bent.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('nl', 'onboarding_7_quote', 'Aliolo heeft de manier waarop mijn kinderen en ik nieuwe onderwerpen beheersen volledig veranderd. De visuele kaarten en gespreide herhaling maken het leren als een spel!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
