INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_1_title', 'Witaj w Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_1_desc', 'Ucz się wizualnie. Opanuj na stałe. Twój wizualny towarzysz nauki oparty na nauce SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_2_title', 'Ile masz lat?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_2_desc', 'Pomoże nam to spersonalizować Twoją naukę i polecić odpowiednie przedmioty.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_3_title', 'Co chcesz opanować?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_3_desc', 'Wybierz swoje główne zainteresowania, aby dostosować swój początkowy pulpit.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_4_title', 'Twórz i udostępniaj') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_4_desc', 'Zbuduj własną talię lub zanurz się w kartach udostępnionych przez uczniów Aliolo na całym świecie. Ucz się we własnym tempie, a następnie sprawdź się, gdy będziesz gotowy.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_5_title', 'Opanuj wszędzie') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_5_desc', 'Twoja biblioteka jest zsynchronizowana na wszystkich Twoich urządzeniach. Powiadomimy Cię tylko wtedy, gdy nadejdzie czas na ochronę Twojej serii.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_6_title', 'Dołącz do społeczności') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_6_desc', 'Zacznij swoją podróż już dziś i opanuj wszystko, co sobie zaplanujesz.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pl', 'onboarding_7_quote', 'Aliolo całkowicie zmieniło sposób, w jaki moje dzieci i ja opanowujemy nowe tematy. Wizualne karty i powtarzanie w odstępach sprawiają, że nauka przypomina zabawę!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
