INSERT INTO ui_translations (lang, key, value) VALUES ('pt', 'onboarding_4_title', 'Criar e Compartilhar') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pt', 'onboarding_4_desc', 'Crie seu próprio baralho ou mergulhe em cartas compartilhadas por alunos do Aliolo em todo o mundo. Aprenda no seu ritmo e teste-se quando estiver pronto.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
