INSERT INTO ui_translations (lang, key, value) VALUES ('pt', 'onboarding_5_desc', 'Sua biblioteca permanece sincronizada em todos os seus dispositivos. Apenas avisaremos quando for a hora de proteger sua sequência.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('pt', 'onboarding_6_title', 'Junte-se à Comunidade') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
