INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_1_title', 'Bun venit la Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_1_desc', 'Învață vizual. Stăpânește permanent. Partenerul tău de învățare vizuală bazat pe știința SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_2_title', 'Câți ani ai?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_2_desc', 'Acest lucru ne ajută să îți personalizăm experiența de învățare și să îți recomandăm subiectele potrivite.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_3_title', 'Ce vrei să stăpânești?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_3_desc', 'Selectează interesul principal pentru a-ți personaliza tabloul de bord inițial.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_4_title', 'Creează și Distribuie') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_4_desc', 'Construiește-ți propriul set sau explorează cardurile partajate de cursanții Aliolo din întreaga lume. Învață în ritmul tău, apoi testează-te când ești gata.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_5_title', 'Stăpânește oriunde') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_5_desc', 'Biblioteca ta rămâne sincronizată pe toate dispozitivele tale. Te vom anunța doar când este timpul să îți protejezi seria.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_6_title', 'Alătură-te comunității') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_6_desc', 'Începe-ți călătoria astăzi și stăpânește orice îți propui.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ro', 'onboarding_7_quote', 'Aliolo a transformat complet modul în care copiii mei și cu mine stăpânim subiecte noi. Cardurile vizuale și repetiția distanțată fac învățarea să pară un joc!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
