INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_1_title', 'Vitajte v Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_1_desc', 'Učte sa vizuálne. Ovládajte trvalo. Váš vizuálny spoločník na učenie poháňaný vedou SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_2_title', 'Koľko máte rokov?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_2_desc', 'To nám pomôže prispôsobiť vaše učenie a odporučiť tie správne predmety.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_3_title', 'Čo chcete ovládnuť?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_3_desc', 'Vyberte svoj primárny záujem a prispôsobte si úvodný panel.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_4_title', 'Vytvárajte a zdieľajte') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_4_desc', 'Zostavte si vlastný balíček alebo sa ponorte do kariet zdieľaných študentmi Aliolo po celom svete. Učte sa vlastným tempom a otestujte sa, keď budete pripravení.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_5_title', 'Ovládajte kdekoľvek') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_5_desc', 'Vaša knižnica zostáva synchronizovaná vo všetkých vašich zariadeniach. Upozorníme vás, len keď bude čas chrániť vašu sériu.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_6_title', 'Pripojte sa ku komunite') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_6_desc', 'Začnite svoju cestu dnes a ovládnite čokoľvek, čo si zaumienite.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_7_quote', 'Aliolo úplne zmenilo spôsob, akým moje deti aj ja ovládame nové témy. Vizuálne karty a rozložené opakovanie robia z učenia hru!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sk', 'onboarding_7_joined', 'Pridali sa tisíce študentov') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
