INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_1_title', 'Dobrodošli v Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_1_desc', 'Učite se vizualno. Obvladajte trajno. Vaš vizualni sopotnik pri učenju, ki ga poganja znanost SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_2_title', 'Koliko ste stari?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_2_desc', 'To nam pomaga prilagoditi vašo učno izkušnjo in priporočiti prave predmete.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_3_title', 'Kaj želite obvladati?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_3_desc', 'Izberite svoje primarno zanimanje, da prilagodite svojo začetno nadzorno ploščo.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_4_title', 'Ustvarite in delite') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_4_desc', 'Sestavite svoj paket ali se potopite v kartice, ki jih delijo učenci Aliolo po vsem svetu. Učite se v svojem tempu, nato pa se preizkusite, ko boste pripravljeni.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_5_title', 'Obvladajte kjerkoli') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_5_desc', 'Vaša knjižnica ostaja sinhronizirana v vseh vaših napravah. Opomnili vas bomo le, ko bo čas za zaščito vašega niza.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_6_title', 'Pridružite se skupnosti') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_6_desc', 'Začnite svojo pot danes in obvladajte vse, kar si zadate.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_7_quote', 'Aliolo je popolnoma spremenil način, kako moji otroci in jaz obvladujemo nove teme. Vizualne kartice in ponavljanje v razmikih naredijo učenje kot igro!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sl', 'onboarding_7_joined', 'Pridružilo se je na tisoče učencev') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
