INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_1_title', 'Tervetuloa Alioloon') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_1_desc', 'Opi visuaalisesti. Hallitse pysyvästi. Visuaalinen oppimiskumppanisi, joka perustuu SM-2-tieteeseen.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_2_title', 'Kuinka vanha olet?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_2_desc', 'Tämä auttaa meitä personoimaan oppimiskokemuksesi ja suosittelemaan oikeita aiheita.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_3_title', 'Mitä haluat hallita?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_3_desc', 'Valitse ensisijainen kiinnostuksesi mukauttaaksesi aloitusnäkymäsi.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_4_title', 'Luo ja jaa') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_4_desc', 'Rakenna oma pakkasi tai sukella Aliolo-oppijoiden jakamiin kortteihin ympäri maailmaa. Opi omaan tahtiisi ja testaa itsesi, kun olet valmis.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_5_title', 'Hallitse missä tahansa') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_5_desc', 'Kirjastosi pysyy synkronoituna kaikilla laitteillasi. Muistutamme sinua vain silloin, kun on aika suojata putkesi.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_6_title', 'Liity yhteisöön') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_6_desc', 'Aloita matkasi tänään ja hallitse mitä tahansa päätätkin.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_7_quote', 'Aliolo on täysin muuttanut tavan, jolla lapseni ja minä hallitsemme uusia aiheita. Visuaaliset kortit ja jaksotettu kertaus saavat oppimisen tuntumaan peliltä!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('fi', 'onboarding_7_joined', 'Tuhannet oppijat ovat liittyneet') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
