INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_1_title', 'Välkommen till Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_1_desc', 'Lär dig visuellt. Bemästra permanent. Din visuella lärkompis som drivs av SM-2-vetenskap.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_2_title', 'Hur gammal är du?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_2_desc', 'Detta hjälper oss att personanpassa din lärandeupplevelse och rekommendera rätt ämnen.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_3_title', 'Vad vill du bemästra?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_3_desc', 'Välj ditt primära intresse för att anpassa din första instrumentpanel.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_4_title', 'Skapa & Dela') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_4_desc', 'Bygg din egen kortlek eller dyk in i kort som delas av Aliolo-lärande över hela världen. Lär dig i din egen takt och testa dig själv när du är redo.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_5_title', 'Bemästra var som helst') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_5_desc', 'Ditt bibliotek förblir synkroniserat över alla dina enheter. Vi påminner dig bara när det är dags att skydda din streak.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_6_title', 'Gå med i gemenskapen') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_6_desc', 'Börja din resa idag och bemästra vad du än tar dig för.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_7_quote', 'Aliolo har helt förändrat sättet som mina barn och jag bemästrar nya ämnen. De visuella korten och den utspridda repetitionen gör att lärandet känns som en lek!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_7_joined', 'Gått med av tusentals lärande') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_next', 'Nästa') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('sv', 'onboarding_skip', 'Hoppa över') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
