INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_1_title', 'Maligayang Pagdating sa Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_1_desc', 'Matuto nang Visual. Master nang Permanente. Ang iyong visual learning companion na pinatatakbo ng SM-2 science.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_2_title', 'Ilang taon ka na?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_2_desc', 'Tinutulungan kami nito na i-personalize ang iyong karanasan sa pag-aaral at irekomenda ang tamang mga paksa.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_3_title', 'Ano ang gusto mong i-master?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_3_desc', 'Piliin ang iyong pangunahing interes upang i-customize ang iyong paunang dashboard.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_4_title', 'Gumawa at Magbahagi') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_4_desc', 'Bumuo ng sarili mong deck o sumisid sa mga card na ibinahagi ng mga nag-aaral ng Aliolo sa buong mundo. Matuto sa sarili mong bilis, pagkatapos ay subukan ang iyong sarili kapag handa ka na.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_5_title', 'I-master Kahit Saan') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_5_desc', 'Nananatiling naka-sync ang iyong library sa lahat ng iyong device. Bibigyan ka lang namin ng nudge kapag oras na para protektahan ang iyong streak.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_6_title', 'Sumali sa Komunidad') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_6_desc', 'Simulan ang iyong paglalakbay ngayon at i-master ang anumang itinakda mo sa iyong isip.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_7_quote', 'Ganap na binago ng Aliolo ang paraan ng pag-master namin ng aking mga anak sa mga bagong paksa. Ang mga visual card at spaced repetition ay nagpaparamdam sa pag-aaral na parang isang laro!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_7_joined', 'Sinalihan ng libu-libong nag-aaral') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
