INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'onboarding_skip', 'Laktawan') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'compare_plans', 'Ipaghambing ang Libre vs Premium') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tl', 'hide_comparison', 'Itago ang Paghahambing ng Plano') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
