INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_1_title', 'Chào mừng bạn đến với Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_1_desc', 'Học qua hình ảnh. Làm chủ vĩnh viễn. Người bạn đồng hành học tập trực quan của bạn được hỗ trợ bởi khoa học SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_2_title', 'Bạn bao nhiêu tuổi?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_2_desc', 'Điều này giúp chúng tôi cá nhân hóa trải nghiệm học tập của bạn và đề xuất các chủ đề phù hợp.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_3_title', 'Bạn muốn làm chủ điều gì?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_3_desc', 'Chọn sở thích chính của bạn để tùy chỉnh bảng điều khiển ban đầu.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_4_title', 'Tạo & Chia sẻ') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_4_desc', 'Xây dựng bộ thẻ của riêng bạn hoặc khám phá các thẻ được chia sẻ bởi những người học Aliolo trên toàn thế giới. Học theo tốc độ của bạn, sau đó tự kiểm tra khi bạn đã sẵn sàng.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_5_title', 'Làm chủ ở mọi nơi') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_5_desc', 'Thư viện của bạn luôn được đồng bộ hóa trên tất cả các thiết bị. Chúng tôi sẽ chỉ nhắc nhở bạn khi đến lúc bảo vệ chuỗi ngày học của mình.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_6_title', 'Tham gia cộng đồng') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_6_desc', 'Bắt đầu hành trình của bạn ngay hôm nay và làm chủ bất cứ điều gì bạn đặt tâm trí vào.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_7_quote', 'Aliolo đã hoàn toàn thay đổi cách các con tôi và tôi làm chủ các chủ đề mới. Các thẻ hình ảnh và sự lặp lại ngắt quãng làm cho việc học giống như một trò chơi!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('vi', 'onboarding_7_joined', 'Được tham gia bởi hàng ngàn người học') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
