INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_1_title', 'Aliolo''ya Hoş Geldiniz') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_1_desc', 'Görsel Olarak Öğrenin. Kalıcı Olarak Ustalaşın. SM-2 bilimi ile güçlendirilmiş görsel öğrenme arkadaşınız.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_2_title', 'Kaç yaşındasınız?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_2_desc', 'Bu, öğrenme deneyiminizi kişiselleştirmemize ve doğru konuları önermemize yardımcı olur.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_3_title', 'Neyde ustalaşmak istiyorsunuz?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_3_desc', 'Başlangıç panelinizi özelleştirmek için ana ilginizi seçin.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_4_title', 'Oluştur ve Paylaş') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_4_desc', 'Kendi destenizi oluşturun veya dünya çapındaki Aliolo öğrencileri tarafından paylaşılan kartlara dalın. Kendi hızınızda öğrenin, hazır olduğunuzda kendinizi test edin.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_5_title', 'Her Yerde Ustalaşın') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_5_desc', 'Kütüphaneniz tüm cihazlarınızda senkronize kalır. Sadece serinizi koruma zamanı geldiğinde sizi uyaracağız.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_6_title', 'Topluluğa Katılın') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_6_desc', 'Yolculuğunuza bugün başlayın ve aklınıza koyduğunuz her şeyde ustalaşın.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_7_quote', 'Aliolo, çocuklarımın ve benim yeni konularda ustalaşma şeklimizi tamamen değiştirdi. Görsel kartlar ve aralıklı tekrar, öğrenmeyi bir oyun gibi hissettiriyor!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('tr', 'onboarding_7_joined', 'Binlerce öğrenci katıldı') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
