INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_1_title', 'Καλώς ήρθατε στο Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_1_desc', 'Μάθετε οπτικά. Κατακτήστε μόνιμα. Ο οπτικός σας σύντροφος μάθησης που υποστηρίζεται από την επιστήμη SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_2_title', 'Πόσο χρονών είστε;') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_2_desc', 'Αυτό μας βοηθά να εξατομικεύσουμε τη μαθησιακή σας εμπειρία και να προτείνουμε τα σωστά θέματα.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_3_title', 'Τι θέλετε να κατακτήσετε;') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_3_desc', 'Επιλέξτε το κύριο ενδιαφέρον σας για να προσαρμόσετε τον αρχικό σας πίνακα ελέγχου.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_4_title', 'Δημιουργία & Κοινή χρήση') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_4_desc', 'Φτιάξτε τη δική σας τράπουλα ή βουτήξτε σε κάρτες που μοιράζονται οι μαθητές του Aliolo σε όλο τον κόσμο. Μάθετε με τον δικό σας ρυθμό και μετά δοκιμάστε τον εαυτό σας όταν είστε έτοιμοι.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_5_title', 'Κατάκτηση παντού') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_5_desc', 'Η βιβλιοθήκη σας παραμένει συγχρονισμένη σε όλες τις συσκευές σας. Θα σας ειδοποιήσουμε μόνο όταν έρθει η ώρα να προστατεύσετε το σερί σας.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_6_title', 'Γίνετε μέλος της κοινότητας') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_6_desc', 'Ξεκινήστε το ταξίδι σας σήμερα και κατακτήστε οτιδήποτε βάλετε στο μυαλό σας.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_7_quote', 'Το Aliolo έχει αλλάξει εντελώς τον τρόπο με τον οποίο τα παιδιά μου και εγώ κατακτούμε νέα θέματα. Οι οπτικές κάρτες και η επανάληψη σε διαστήματα κάνουν τη μάθηση να μοιάζει με παιχνίδι!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_7_joined', 'Συμμετέχουν χιλιάδες μαθητές') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_next', 'Επόμενο') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'onboarding_skip', 'Παράλειψη') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'compare_plans', 'Σύγκριση Δωρεάν έναντι Premium') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('el', 'hide_comparison', 'Απόκρυψη σύγκρισης προγραμμάτων') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
