INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_1_title', 'Ласкаво просимо до Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_1_desc', 'Навчайтеся візуально. Опановуйте назавжди. Ваш супутник для візуального навчання на базі науки SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_2_title', 'Скільки вам років?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_2_desc', 'Це допоможе нам персоналізувати ваш досвід навчання та рекомендувати відповідні предмети.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_3_title', 'Що ви хочете опанувати?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_3_desc', 'Виберіть свій основний інтерес, щоб налаштувати початкову панель керування.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_4_title', 'Створюйте та діліться') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_4_desc', 'Створюйте власні колоди або занурюйтеся в картки, якими діляться учні Aliolo по всьому світу. Навчайтеся у своєму темпі, а потім перевірте себе, коли будете готові.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_5_title', 'Опановуйте будь-де') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_5_desc', 'Ваша бібліотека синхронізується на всіх ваших пристроях. Ми нагадаємо вам лише тоді, коли прийде час захистити вашу серію.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_6_title', 'Приєднуйтесь до спільноти') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_6_desc', 'Почніть свою подорож сьогодні та опануйте все, що задумаєте.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_7_quote', 'Aliolo повністю змінив те, як мої діти та я опановуємо нові теми. Візуальні картки та інтервальні повторення роблять навчання схожим на гру!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('uk', 'onboarding_7_joined', 'Приєдналися тисячі учнів') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
