INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_1_title', 'مرحباً بك في Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_1_desc', 'تعلم بصرياً. أتقن بشكل دائم. رفيقك في التعلم البصري المدعوم بعلم SM-2.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_2_title', 'كم عمرك؟') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_2_desc', 'هذا يساعدنا على تخصيص تجربة التعلم الخاصة بك والتوصية بالمواد المناسبة.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_3_title', 'ماذا تريد أن تتقن؟') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_3_desc', 'حدد اهتمامك الأساسي لتخصيص لوحة التحكم الأولية الخاصة بك.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_4_title', 'الإنشاء والمشاركة') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_4_desc', 'قم ببناء مجموعتك الخاصة أو استكشف البطاقات التي يشاركها متعلمو Aliolo في جميع أنحاء العالم. تعلم بالسرعة التي تناسبك، ثم اختبر نفسك عندما تكون مستعداً.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_5_title', 'الإتقان في أي مكان') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_5_desc', 'تظل مكتبتك متزامنة عبر جميع أجهزتك. سنقوم فقط بتذكيرك عندما يحين الوقت لحماية سلسلتك.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_6_title', 'انضم إلى المجتمع') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_6_desc', 'ابدأ رحلتك اليوم وأتقن أي شيء تضعه في اعتبارك.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_7_quote', 'لقد غيرت Aliolo تماماً الطريقة التي أتقن بها أنا وأطفالي موضوعات جديدة. البطاقات المرئية والتكرار المتباعد يجعل التعلم يبدو وكأنه لعبة!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_7_joined', 'انضم إليه آلاف المتعلمين') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_next', 'التالي') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ar', 'onboarding_skip', 'تخطي') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
