INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_1_title', 'Aliolo में आपका स्वागत है') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_1_desc', 'विजुअल सीखें। स्थायी रूप से महारत हासिल करें। SM-2 विज्ञान द्वारा संचालित आपका विजुअल लर्निंग साथी।') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_2_title', 'आपकी उम्र क्या है?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_2_desc', 'यह हमें आपके सीखने के अनुभव को व्यक्तिगत बनाने और सही विषयों की सिफारिश करने में मदद करता है।') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_3_title', 'आप किसमें महारत हासिल करना चाहते हैं?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_3_desc', 'अपने शुरुआती डैशबोर्ड को कस्टमाइज़ करने के लिए अपनी प्राथमिक रुचि चुनें।') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_4_title', 'बनाएं और साझा करें') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_4_desc', 'अपना खुद का डेк बनाएं या दुनिया भर में Aliolo सीखने वालों द्वारा साझा किए गए कार्डों में गोता लगाएँ। अपनी गति से सीखें, फिर तैयार होने पर खुद का परीक्षण करें।') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_5_title', 'कहीं भी महारत हासिल करें') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_5_desc', 'आपकी लाइब्रेरी आपके सभी डिवाइसों में सिंक रहती है। जब आपकी स्ट्रीक को सुरक्षित करने का समय होगा, तब हम आपको केवल संकेत देंगे।') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_6_title', 'समुदाय में शामिल हों') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_6_desc', 'आज ही अपनी यात्रा शुरू करें और जो कुछ भी आप अपने मन में ठान लें, उसमें महारत हासिल करें।') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_7_quote', 'Aliolo ने मेरे बच्चों और मेरे नए विषयों में महारत हासिल करने के तरीके को पूरी तरह से बदल दिया है। विजुअल कार्ड और अंतराल पुनरावृत्ति सीखने को एक खेल की तरह महसूस कराते हैं!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('hi', 'onboarding_7_joined', 'हजारों शिक्षार्थियों द्वारा शामिल हुए') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
