INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_1_title', '欢迎来到 Aliolo') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_1_desc', '视觉化学习，永久掌握。由 SM-2 科学支持的视觉学习伴侣。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_2_title', '你多大了？') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_2_desc', '这有助于我们个性化你的学习体验并推荐合适的主题。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_3_title', '你想掌握什么？') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_3_desc', '选择你的主要兴趣以自定义初始仪表板。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_4_title', '创建与分享') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_4_desc', '构建你自己的卡组或深入研究全球 Aliolo 学习者分享的卡片。按照你自己的节奏学习，然后在准备好时测试自己。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_5_title', '随时随地掌握') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_5_desc', '你的库在所有设备上保持同步。我们只会在需要保护你的连续记录时提醒你。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_6_title', '加入社区') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_6_desc', '今天就开始你的旅程，掌握你下定决心要做的任何事情。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('zh', 'onboarding_7_quote', 'Aliolo 完全改变了我及我的孩子掌握新主题的方式。视觉卡片和间隔重复让学习感觉像是一场游戏！') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
