INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_1_title', 'Alioloへようこそ') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_1_desc', '視覚的に学び、永続的に習得。SM-2科学に基づいた、あなたの視覚学習コンパニオン。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_2_title', '年齢を教えてください。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_2_desc', '学習体験をパーソナライズし、最適な主題を推奨するのに役立ちます。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_3_title', '何を習得したいですか？') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_3_desc', '主な興味を選択して、初期ダッシュボードをカスタマイズします。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_4_title', '作成と共有') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_4_desc', '自分だけのデッキを作ったり、世界中のAliolo学習者が共有するカードに飛び込んだりできます。自分のペースで学び、準備ができたらテストしましょう。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_5_title', 'どこでも習得') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_5_desc', 'ライブラリはすべてのデバイスで同期されます。学習の継続記録を守る時期になったときだけ通知します。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_6_title', 'コミュニティに参加') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_6_desc', '今日から旅を始めて、決心したことを何でも習得しましょう。') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_7_quote', 'Alioloは、私と子供たちが新しいトピックを習得する方法を完全に変えました。視覚的なカードと間隔を空けた反復練習で、学習がゲームのように感じられます！') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ja', 'onboarding_7_joined', '数千人の学習者が参加中') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
