INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_1_title', 'Aliolo에 오신 것을 환영합니다') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_1_desc', '시각적으로 배우고 영구적으로 마스터하세요. SM-2 과학으로 강화된 시각 학습 도우미입니다.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_2_title', '나이가 어떻게 되시나요?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_2_desc', '학습 경험을 개인화하고 적절한 주제를 추천하는 데 도움이 됩니다.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_3_title', '무엇을 마스터하고 싶으신가요?') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_3_desc', '초기 대시보드를 사용자 정의하려면 주요 관심사를 선택하세요.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_4_title', '만들기 및 공유') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_4_desc', '나만의 덱을 만들거나 전 세계 Aliolo 학습자들이 공유한 카드를 살펴보세요. 자신의 속도에 맞춰 배우고 준비가 되면 테스트해보세요.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_5_title', '어디서나 마스터하기') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_5_desc', '라이브러리는 모든 장치에서 동기화됩니다. 연속 기록을 지켜야 할 때만 알려드립니다.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_6_title', '커뮤니티 가입') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_6_desc', '오늘부터 여정을 시작하고 마음먹은 무엇이든 마스터하세요.') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_7_quote', 'Aliolo는 저와 아이들이 새로운 주제를 마스터하는 방식을 완전히 바꾸어 놓았습니다. 시각적 카드와 간격 반복 덕분에 학습이 게임처럼 느껴집니다!') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
INSERT INTO ui_translations (lang, key, value) VALUES ('ko', 'onboarding_7_joined', '수천 명의 학습자가 가입함') ON CONFLICT (lang, key) DO UPDATE SET value = EXCLUDED.value;
